head.script:
//---------------------------------------------------------
// hidden 영역 전역변수 처리
//---------------------------------------------------------
scwin.txt_countRow = "";
scwin.hid_kcomcd = $c.data.getParameter("kcomcd");
scwin.hd_sendYn = ""

scwin.paramData = {};
scwin.p_blno = $c.data.getParameter("blno");

scwin.onpageload = function () {
};
scwin.onUdcCompleted = function () {
    txt_mfdpnm.setDisabled(true);
    txt_mfdsnm.setDisabled(true);
    txt_dpnmNd.setDisabled(true);
    txt_dsnmNd.setDisabled(true);
    scwin.compEditMode(true);
    $c.gus.cfDisableBtnOnly([b_Update, b_Delete, b_Cancel, b_Create, b_Save]);

    $c.util.setTimeout(() => {
        scwin.f_Set("INIT");
        scwin.f_getParametrSetting();
    }, { delay: 400 });
}
//---------------------------------------------------------
// 사용자 함수
//---------------------------------------------------------
scwin.f_getParametrSetting = function () {
    scwin.paramData = $c.data.getParameter();

    var blno = scwin.paramData.blno == null ? "" : scwin.paramData.blno;

    if (blno == "") {
        return false;
    }

    cnd_ed_mblno.setValue(blno);
    scwin.btn_search_onclick();
}

scwin.f_RetrieveAms2 = function (row) {
    txt_dpnmNd.setValue("");
    txt_dsnmNd.setValue("");
    ds_AirAmsHouseInfoSearch.setEmptyValue();
    ds_AirAmsHouseInfoSearch.set("kcomcd", ds_AirAmsHouseInfo.getCellData(row, "kcomcd"));
    ds_AirAmsHouseInfoSearch.set("mblno", ds_AirAmsHouseInfo.getCellData(row, "mblno"));
    ds_AirAmsHouseInfoSearch.set("mhno", ds_AirAmsHouseInfo.getCellData(row, "mhno"));
    ds_AirAmsHouseInfoSearch.set("blno", ds_AirAmsHouseInfo.getCellData(row, "blno"));

    $c.sbm.execute(sbm_retrieve2);
}

scwin.f_Set = function (gubun) {
    switch (gubun) {
        case "INIT": //초기화
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            $c.gus.cfDisableBtnOnly([b_Create, b_Cancel, b_Update, b_Save, b_Delete]);
            $c.gus.cfDisableObjects([txt_dsnmNd, txt_dpnmNd, txt_mfdsnm, txt_mfdpnm]);
            scwin.f_DisablePopUpObj();
            break;
        case "RETRIEVE":  //조회모드	
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            scwin.compEditMode(true);
            $c.gus.cfEnableBtnOnly([b_Create]);
            $c.gus.cfDisableBtnOnly([b_Cancel, b_Update, b_Save, b_Delete]);
            scwin.f_DisablePopUpObj();
            break;
        case "RETRIEVE2":  //조회모드	
            $c.gus.cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            scwin.compEditMode(true);
            $c.gus.cfEnableBtnOnly([b_Update, b_Delete]);
            $c.gus.cfDisableBtnOnly([b_Cancel, b_Create, b_Save]);
            scwin.f_DisablePopUpObj();
            break;
        case "CREATE":
            $c.gus.cfEnableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            scwin.compEditMode(false);
            $c.gus.cfEnableBtnOnly([b_Save, b_Cancel]);
            $c.gus.cfDisableBtnOnly([b_Delete, b_Update, b_Create]);
            scwin.f_EnablePopUpObj();
            break;
        case "UPDATE":
            $c.gus.cfEnableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            scwin.compEditMode(false);
            $c.gus.cfEnableBtnOnly([b_Save, b_Delete, b_Cancel]);
            $c.gus.cfDisableBtnOnly([b_Update, b_Create]);
            scwin.f_EnablePopUpObj();
            break;
        case "DELETE":
            cfDisableKeyData();  // Key와 Data를 모두 disable(non-editable) 상태로 변경한다.
            cfEnableBtnOnly([b_Delete]);
            cfDisableBtnOnly([b_Update, b_Create, b_Save, b_Cancel]);
            scwin.f_DisablePopUpObj();
            break;
    }
}

scwin.f_DisablePopUpObj = function () {
    $c.gus.cfDisableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6]);
}

scwin.f_EnablePopUpObj = function () {
    $c.gus.cfEnableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6]);
}

