scwin.f_ChkPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이	입력이 안된	경우, 해당 Text	Box가 readonly 인 경우,	이전값과 동일한	경우 팝업을	실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;
    // 짝이	되는 오브젝트의	값 제거
    $c.gus.cfClearPairObj(pairObj);
    // inObj가 코드	필드일 경우	팝업
    if (isCode == null || isCode == true) {
        scwin.f_PopUp(disGubun, 'T', 'F', 'F');
    }
    // inObj가 코드명 필드일 경우 팝업
    else {
        scwin.f_PopUp(disGubun, 'T', 'F', 'F');
    }
}

scwin.f_sendEDI = async function () {
    // 조회된 데이터가 있는지 검증 
    if (ds_AirAms2List.getTotalRow() == 0) {
        await $c.win.alert("There is no Date. Master B/L No Seach Fist~!!!!");
        return;
    }

    // 체크한 데이터가 있는지 검증 

    if (gr_AirAmsHouseInfo.getCheckedIndex("chk").length == 0) {
        await $c.win.alert("There is no Choice~!!!");
        return;
    }

    for (var i = 0; i < ds_AirAmsHouseInfo.getTotalRow(); i++) {
        if (ds_AirAmsHouseInfo.getCellData(i, "chk") == "T") {

            if (ds_AirAmsHouseInfo.getCellData(i, "sendYn") == "0" || ds_AirAmsHouseInfo.getCellData(i, "sendYn") == "1") {
                await $c.win.alert("Line => " + (i + 1) + " is Already Sended");
                return;
            }

            scwin.f_RetrieveAms2(i);
            ds_AirAms2List.setJSON([]);
            ds_AirAms2List.setRowJSON(0, ds_AirAms2.getJSON());
            ds_AirAms2List.setCellData(gr_AirAmsHouseInfo.getFocusedRowIndex(), "sendYn", "0.0");
            ds_AirAms2List.modifyRowStatus(0, "C");
            await $c.sbm.execute(sbm_EdiSend);
        }
    }
    $c.sbm.execute(sbm_retrieve);
}

