scwin.f_ReqFieldChk = async function () {
    if (await $c.gus.cfValidate([tb_headerMandantory]) == false) {
        return false;
    }
    if (await $c.gus.cfValidate([tb_HouseMandantory]) == false) {
        return false;
    }
    if (await $c.gus.cfValidate([tb_ShipperMandatory]) == false) {
        return false;
    }
    if (await $c.gus.cfValidate([tb_ConsigneeMandatory]) == false) {
        return false;
    }

    return true;
}

scwin.setDate = function (d, fd, r, c) {
    if (d == "") return "";
    data = d.substr(0, 8);
    return data.substr(0, 4) + "/" + data.substr(4, 2) + "/" + data.substr(6, 2);
}
