scwin.btn_search_onclick = function (e) {
    txt_mfdpnm.setValue("");
    txt_mfdsnm.setValue("");
    if (cnd_ed_mblno.getValue().trim() == "") {
        $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Master B/L No"]);
        cnd_ed_mblno.focus();
        return;
    }
    ds_Search.set("kcomcd", scwin.hid_kcomcd);
    ds_Search.set("mblno", cnd_ed_mblno.getValue());

    $c.sbm.execute(sbm_retrieve);
};

