scwin.sbm_retrieve_submitdone = function (e) {
    if (ds_AirAmsList.getTotalRow() < 1) {
        return;
    } else {
        ds_AirAms.setJSON(ds_AirAmsList.getRowJSON(0));
    }

    ed_totCnt.setValue(ds_AirAmsHouseInfo.getTotalRow());
    gr_AirAmsHouseInfo.setFocusedCell(0, 2);
    //검색 후 명값 넣어줌
    if (ed_mfdpcd.getValue().length > 0 || txt_mfdpnm.getValue().length > 0) {
        scwin.f_PopUp('MasterPortCode', 'T', 'F', 'F');
    }
    if (ed_mfdscd.getValue().length > 0 || txt_mfdsnm.getValue().length > 0) {
        scwin.f_PopUp('MasterPortCode2', 'T', 'F', 'F');
    }
    if (ds_AirAmsHouseInfo.getCellData(ds_AirAmsHouseInfo.getRowPosition(), "flag") == "2") {// BL에서 정보를 가져올때
        gr_AirAmsHouseInfo.setColumnReadOnly("chk", false);
        scwin.f_Set("RETRIEVE2");
    } else {
        gr_AirAmsHouseInfo.setColumnReadOnly("chk", true)
        scwin.f_Set("RETRIEVE");
    }
    scwin.f_RetrieveAms2(0);
}

scwin.sbm_retrieve2_submitdone = function (e) {
    if (ds_AirAms2List.getTotalRow() < 1) {
        return;
    } else {
        ds_AirAms2.setJSON(ds_AirAms2List.getRowJSON(0));
    }

    //검색 후 명값 넣어줌
    if (ed_dpcd.getValue().length > 0 || txt_dpnmNd.getValue().length > 0) {
        scwin.f_PopUp('HousePortCode', 'T', 'F', 'F');
    }
    if (ed_dscd.getValue().length > 0 || txt_dsnmNd.getValue().length > 0) {
        scwin.f_PopUp('HousePortCode2', 'T', 'F', 'F');
    }
    if (ds_AirAmsHouseInfo.getCellData(gr_AirAmsHouseInfo.getFocusedRowIndex(), "flag") == "1") {//BL에서 정보를 가져올때
        if (ed_shCode.getValue().length > 0) {
            scwin.f_PopUp('ShipperClntInfo', 'T', 'F', 'F');
        }
        if (ed_cnCode.getValue().length > 0) {
            scwin.f_PopUp('ConsigneeClntInfo', 'T', 'F', 'F');
        }
    }

    if (ds_AirAmsHouseInfo.getCellData(ds_AirAmsHouseInfo.getRowPosition(), "flag") == "2") {// BL에서 정보를 가져올때
        gr_AirAmsHouseInfo.setColumnReadOnly("chk", false);
        scwin.f_Set("RETRIEVE2");
    } else {
        gr_AirAmsHouseInfo.setColumnReadOnly("chk", true)
        scwin.f_Set("RETRIEVE");
    }
}

