scwin.b_Save_onclick = async function (e) {
    if (await scwin.f_ReqFieldChk()) {

        var cnStreet = ds_AirAms2.get("cnStreet");
        var shStreet = ds_AirAms2.get("shStreet");
        var shName = ds_AirAms2.get("shName");
        var item = ds_AirAms2.get("item");

        if (item.length > 35) {
            await $c.win.alert('a');
            item = item.cut(35, item.length - 35);
            ds_AirAms2.set("item", item);
        }
        if (cnStreet.length > 35) {
            cnStreet = cnStreet.cut(35, cnStreet.length - 35);
            ds_AirAms2.set("cnStreet", cnStreet);
        }
        if (shStreet.length > 35) {
            shStreet = shStreet.cut(35, shStreet.length - 35);
            ds_AirAms2.set("shStreet", shStreet);
        }
        if (shName.length > 35) {
            shName = shName.cut(35, shName.length - 35);
            ds_AirAms2.set("shName", shName);
        }
        ds_AirAmsList.setJSON([]);
        // ds_AirAmsList.insertRow();
        ds_AirAmsList.setRowJSON(0, ds_AirAms.getJSON());
        ds_AirAmsList.setCellData(0, "kcomcd", "DBEX");
        ds_AirAmsList.modifyRowStatus(0, "U");
        ds_AirAms2List.setJSON([]);
        // ds_AirAms2List.insertRow();
        ds_AirAms2List.setRowJSON(0, ds_AirAms2.getJSON());
        ds_AirAms2List.setCellData(0, "kcomcd", "DBEX");
        ds_AirAms2List.modifyRowStatus(0, "U");
        if (ds_AirAms.get("flag") == "2") {
            ds_AirAmsList.modifyRowStatus(0, "C");
            ds_AirAms2List.modifyRowStatus(0, "C");
        }
        if (ds_AirAmsHouseInfo.getCellData(ds_AirAmsHouseInfo.getRowPosition(), "flag") == "1") {
            ds_AirAmsList.modifyRowStatus(0, "C");
            ds_AirAms2List.modifyRowStatus(0, "C");
        }

        await $c.sbm.execute(sbm_save);
        await $c.win.alert("성공적으로 저장하였습니다.");
        scwin.btn_search_onclick();
    }
};

scwin.b_Delete_onclick = async function (e) {
    if (await $c.win.confirm(MSG_CM_CRM_004)) {  //삭제하시겠습니까?
        ds_AirAmsList.modifyRowStatus(0, "D");
        ds_AirAms2List.modifyRowStatus(0, "D");
        await $c.sbm.execute(sbm_save);
        await $c.win.alert("성공적으로 저장하였습니다.");
        scwin.btn_search_onclick();
    }
};

