scwin.gr_AirAmsHouseInfo_onheaderclick = function (headerId) {

    if (headerId == "chk") {
        var bCheck = gr_AirAmsHouseInfo.getHeaderValue("chk")
        var rowCnt = ds_AirAmsHouseInfo.getRowCount();

        for (var i = 0; i < rowCnt; i++) {
            if (bCheck) {
                if (ds_AirAmsHouseInfo.getCellData(i, "flag") == '2') {
                    ds_AirAmsHouseInfo.setCellData(i, "chk", "T");
                } else {
                    ds_AirAmsHouseInfo.setCellData(i, "chk", "F");
                }
            } else {
                ds_AirAmsHouseInfo.setCellData(i, "chk", "F");
            }
        }
    }
};

